 21→    const likes = journal?.like_count?.[0]?.count || 0;
 22→    const comments = journal?.comment_count?.[0]?.count || 0;
 23→    const bookmarks = journal?.bookmark_count?.[0]?.count || 0;
 24→    const views = journal?.views || 0;
 25→
