202→
203→    const isSearchMode = committedSearchQuery.length >= 2;
204→
205→    const { data: feedData, isLoading: isLoadingFeed } = useQuery({
206→        queryKey: ["explore-hottest-monthly-feed", userId, currentUtcMonthKey],
207→        queryFn: () => getMonthlyHottestJournals(userId, 10),
208→        refetchOnWindowFocus: false,
209→        staleTime: 15 * 1000,
210→    });
211→
212→    const {
213→        data: searchData,
214→        isLoading: isLoadingSearch,
215→        isFetching: isFetchingSearch,
216→        error: searchError,
217→    } = useQuery({
218→        queryKey: ["explore-search", userId, committedSearchQuery],
219→        queryFn: () => searchJournals(committedSearchQuery, 10, userId),
220→        enabled: isSearchMode,
221→        refetchOnWindowFocus: false,
222→        staleTime: 10 * 1000,
