230→        queryFn: () => searchJournals(debouncedSearchInput, 6, userId),
231→        enabled: debouncedSearchInput.length >= 2 && isSearchFocused,
232→        refetchOnWindowFocus: false,
233→        staleTime: 10 * 1000,
234→    });
235→
236→    const journals = isSearchMode ? (searchData?.data || []) : (feedData?.data || []);
237→    const isLoading = isSearchMode ? isLoadingSearch : isLoadingFeed;
238→    const suggestionItems = suggestionData?.data || [];
239→    const showSuggestions = isSearchFocused && debouncedSearchInput.length >= 2;
240→
241→    const handleSubmitSearch = (rawQuery) => {
242→        const normalizedQuery = typeof rawQuery === "string" ? rawQuery.trim() : "";
243→        if(normalizedQuery.length < 2){
244→            setCommittedSearchQuery("");
245→            return;
246→        }
247→
248→        setCommittedSearchQuery(normalizedQuery);
249→        setSearchInput(normalizedQuery);
250→        setIsSearchFocused(false);
251→    };
252→
253→    const handleClearSearch = () => {
