255→        setDebouncedSearchInput("");
256→        setCommittedSearchQuery("");
257→        setIsSearchFocused(false);
258→    };
259→
260→    const handleSearchInputKeyDown = (e) => {
261→        if(e.key === "Enter"){
262→            e.preventDefault();
263→            handleSubmitSearch(searchInput);
264→        }
265→
266→        if(e.key === "Escape"){
267→            setIsSearchFocused(false);
268→        }
269→    };
270→
271→    const handleClickSuggestion = (journal) => {
272→        if(!journal?.id){
273→            return;
274→        }
275→        if(!session){
276→            openAuthModal();
277→            return;
278→        }
279→        setIsSearchFocused(false);
